+fn build_auth_required_audit_decision_context(
+    execution_id: &str,
+    pane_id: u64,
+    agent_type: &str,
+    event_type: &str,
+    rule_id: Option<&str>,
+    strategy: &AuthRecoveryStrategy,
+    cass_lookup: &AuthCassHintsLookup,
+    input_summary: &str,
+    result: &str,
+    timestamp_ms: i64,
+) -> Option<String> {
+    let mut context = new_workflow_handler_audit_context(
